"""FastAPI framework, high performance, easy to learn, fast to code, ready for production."""
from __future__ import annotations

from typing import Any, Callable, Coroutine, Dict, List, Optional, Sequence, Type, Union
from contextlib import asynccontextmanager
from collections.abc import AsyncGenerator, Awaitable

from fastapi.routing import APIRouter
from fastapi.exceptions import HTTPException, RequestValidationError
from starlette.applications import Starlette
from starlette.middleware import Middleware
from starlette.requests import Request
from starlette.responses import JSONResponse, Response
from starlette.routing import BaseRoute
from starlette.types import ASGIApp, Lifespan


class FastAPI(Starlette):
    """
    FastAPI application class.

    Usage::

        from fastapi import FastAPI

        app = FastAPI()

        @app.get("/")
        def read_root():
            return {"Hello": "World"}
    """

    def __init__(
        self,
        *,
        debug: bool = False,
        routes: Optional[List[BaseRoute]] = None,
        title: str = "FastAPI",
        summary: Optional[str] = None,
        description: str = "",
        version: str = "0.1.0",
        openapi_url: Optional[str] = "/openapi.json",
        openapi_tags: Optional[List[Dict[str, Any]]] = None,
        servers: Optional[List[Dict[str, Any]]] = None,
        dependencies: Optional[Sequence[Any]] = None,
        default_response_class: Type[Response] = JSONResponse,
        docs_url: Optional[str] = "/docs",
        redoc_url: Optional[str] = "/redoc",
        swagger_ui_oauth2_redirect_url: Optional[str] = "/docs/oauth2-redirect",
        swagger_ui_init_oauth: Optional[Dict[str, Any]] = None,
        middleware: Optional[Sequence[Middleware]] = None,
        lifespan: Optional[Lifespan["FastAPI"]] = None,
    ) -> None:
        self.title = title
        self.summary = summary
        self.description = description
        self.version = version
        self.openapi_url = openapi_url
        self.openapi_tags = openapi_tags or []
        self.servers = servers or []
        self.docs_url = docs_url
        self.redoc_url = redoc_url
        self.router = APIRouter(
            routes=routes,
            dependency_overrides_provider=self,
            default_response_class=default_response_class,
        )

    def include_router(
        self,
        router: "APIRouter",
        *,
        prefix: str = "",
        tags: Optional[List[str]] = None,
        dependencies: Optional[Sequence[Any]] = None,
        responses: Optional[Dict[Union[int, str], Dict[str, Any]]] = None,
    ) -> None:
        """Include another router in this router."""
        self.router.include_router(
            router,
            prefix=prefix,
            tags=tags,
            dependencies=dependencies,
            responses=responses,
        )

    def get(self, path: str, **kwargs: Any) -> Callable:
        return self.router.get(path, **kwargs)

    def post(self, path: str, **kwargs: Any) -> Callable:
        return self.router.post(path, **kwargs)

    def put(self, path: str, **kwargs: Any) -> Callable:
        return self.router.put(path, **kwargs)

    def delete(self, path: str, **kwargs: Any) -> Callable:
        return self.router.delete(path, **kwargs)

    def patch(self, path: str, **kwargs: Any) -> Callable:
        return self.router.patch(path, **kwargs)
